import { createTheme, type ThemeOptions } from '@mui/material';
import { cloneDeep, merge } from 'lodash-es';
import { useCallback } from 'react';
import type { AppDensityMode, AppTheme, AppThemeConfigs } from '../..';
import { getDensityThemeOverrides } from '../density';

/**
 * Baseline MUI `ThemeOptions` applied to every theme produced by
 * {@link useAppThemeBuilder} before any application or density overrides.
 *
 * - Registers the TUI-specific `zIndex.tui.superOverlay` slot used by overlay components.
 * - Forces `html`, `body`, and `#root` to fill the viewport so the app shell can rely on a
 *   full-height layout container.
 * - Removes the right border on `MuiDrawer` paper so the left navigation blends with the
 *   surrounding surface.
 *
 * This is merged first in the precedence chain:
 * `BASE_THEME_CONFIG` → density overrides → theme `global` → `globalOverrides` →
 * theme `light`/`dark` → `light`/`dark` overrides.
 */
const BASE_THEME_CONFIG: Partial<ThemeOptions> = {
  zIndex: {
    tui: {
      superOverlay: 2000
    }
  },
  components: {
    MuiCssBaseline: {
      styleOverrides: {
        html: {
          width: '100%',
          height: '100%'
        },
        body: {
          width: '100%',
          height: '100%'
        },
        '#root': {
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0
        }
      }
    },
    MuiDrawer: {
      styleOverrides: {
        paper: {
          borderRightColor: 'transparent'
        }
      }
    }
  }
};

/**
 * Additional positional arguments forwarded to MUI's `createTheme(options, ...args)`.
 *
 * Typically used to pass MUI locale packs (e.g. `frFR` from `@mui/material/locale`,
 * `@mui/x-data-grid/locales`, `@mui/x-date-pickers/locales`) so component
 * `defaultProps` localized strings are merged into the resulting theme.
 */
export type AppThemeLocalization = object[];

/**
 * Returns a memoized builder that produces a paired light/dark MUI `Theme` for the
 * application.
 *
 * The builder deep-merges configuration in the following precedence (lowest to highest):
 * 1. {@link BASE_THEME_CONFIG} — TUI baseline.
 * 2. Density overrides resolved from `density` via `getDensityThemeOverrides`.
 * 3. `theme.configs.global` — theme-level options shared across modes.
 * 4. `optionsOverride.global` — caller-supplied global overrides.
 * 5. `theme.configs.light` / `theme.configs.dark` — mode-specific options.
 * 6. `optionsOverride.light` / `optionsOverride.dark` — caller-supplied mode overrides.
 *
 * The merged options are then passed to `createTheme(options, ...localization)`, where
 * `localization` forwards MUI locale packs (see {@link AppThemeLocalization}) so component
 * `defaultProps` translated strings are applied.
 *
 * All inputs are deep-cloned before merging to prevent mutation of caller-owned config
 * objects across renders.
 *
 * @returns A stable callback `(theme, optionsOverride, density?, localization?) => { lightTheme, darkTheme }`.
 */
export const useAppThemeBuilder = () => {
  return useCallback(
    (
      theme: AppTheme,
      optionsOverride: Partial<AppThemeConfigs>,
      density: AppDensityMode = 'comfortable',
      localization: AppThemeLocalization = []
    ) => {
      // Need to ensure deeply merged object aren't hanging around.
      const baseConfigs = cloneDeep(BASE_THEME_CONFIG);
      const densityOverrides = getDensityThemeOverrides(density);
      const { light, dark, global } = cloneDeep(theme.configs);

      const { light: lightOverrides, dark: darkOverrides, global: globalOverrides } = cloneDeep(optionsOverride) || {};

      return {
        lightTheme: createTheme(
          merge(
            {},
            baseConfigs,
            densityOverrides,
            global || null,
            globalOverrides || null,
            light || null,
            lightOverrides || null
          ),
          ...localization
        ),
        darkTheme: createTheme(
          merge(
            {},
            baseConfigs,
            densityOverrides,
            global || null,
            globalOverrides || null,
            dark || null,
            darkOverrides || null
          ),
          ...localization
        )
      };
    },
    []
  );
};
