import { ZoomOutMap } from '@mui/icons-material';
import {
  Box,
  ClickAwayListener,
  Divider,
  Fade,
  IconButton,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  ListSubheader,
  Paper,
  Popper,
  Tooltip,
  Typography,
  useTheme
} from '@mui/material';
import { useCallback, useEffect, useRef, useState, type ReactElement } from 'react';
import { useTranslation } from 'react-i18next';
import { useAppLayout, useAppPreferences, useAppUser } from '../../app/hooks';
import { useAppRouter } from '../../app/hooks/useAppRouter';
import { AppAvatar, AppUserAvatar } from '../../display/AppAvatar';
import { MODULE_NAME } from '../../name';
import { OverlayShadow } from '../../overlay/OverlayShadow';
import type { AppBarUserMenuElement } from '../../topnav';
import ThemeSelection from '../../topnav/theme/ThemeSelection';

type AppBarUserMenuType = 'usermenu' | 'adminmenu';

export const UserProfile = () => {
  const theme = useTheme();
  const anchorRef = useRef<HTMLButtonElement>(undefined);
  const layout = useAppLayout();

  const { location, Link } = useAppRouter();
  const { t: clientT } = useTranslation();
  const { t } = useTranslation(MODULE_NAME);
  const { user } = useAppUser();
  const { allowPersonalization, allowTranslate, allowReset, allowFocusMode, topnav } = useAppPreferences();

  const [open, setOpen] = useState<boolean>(false);

  const hasContentBeforeUserMenu =
    Boolean(topnav.profile?.slots?.top?.length) ||
    allowFocusMode ||
    Boolean(topnav.profile?.slots?.userMenu?.before?.length);

  const renderSlot = useCallback((id: string, slot?: ReactElement[]) => {
    return (
      <OverlayShadow region="slot" id={id}>
        {slot}
      </OverlayShadow>
    );
  }, []);

  const renderFocusMode = useCallback(() => {
    if (!allowFocusMode) {
      return null;
    }

    return (
      <List dense disablePadding>
        <Tooltip title={t('personalization.focus.mode.tooltip')} placement="top">
          <ListItem disablePadding>
            <ListItemButton onClick={() => layout.setFocus(_focus => !_focus)} id="personalization-focusmode">
              <ListItemIcon>
                <ZoomOutMap />
              </ListItemIcon>
              <ListItemText>{t('personalization.focus.mode.label')}</ListItemText>
            </ListItemButton>
          </ListItem>
        </Tooltip>
      </List>
    );
  }, [allowFocusMode, layout, t]);

  const renderThemeSelection = useCallback(
    (enabled: boolean) => {
      if (enabled && (allowPersonalization || allowTranslate || allowReset)) {
        return (
          <div>
            <Divider />
            <ThemeSelection />
          </div>
        );
      }
      return null;
    },
    [allowPersonalization, allowTranslate, allowReset]
  );

  const renderMenu = useCallback(
    (
      type: AppBarUserMenuType,
      menuItems: AppBarUserMenuElement[],
      title: string,
      i18nKey: string,
      withDivider: boolean = true,
      dividerTopSpacing: boolean = false
    ) => {
      if (menuItems !== undefined && menuItems !== null && menuItems.length !== 0) {
        return (
          <div>
            {withDivider && <Divider sx={dividerTopSpacing ? { mt: 1 } : undefined} />}
            <List dense subheader={<ListSubheader disableSticky>{i18nKey ? clientT(i18nKey) : title}</ListSubheader>}>
              {menuItems.map((a, i) =>
                a.element ? (
                  <ListItem key={`${type}-${i}`}>{a.element}</ListItem>
                ) : (
                  <ListItemButton component={Link} to={a.route} key={`${type}-${i}`}>
                    {a.icon && <ListItemIcon>{a.icon}</ListItemIcon>}
                    <ListItemText>{a.i18nKey ? clientT(a.i18nKey) : a.title}</ListItemText>
                  </ListItemButton>
                )
              )}
            </List>
          </div>
        );
      }
      return null;
    },
    [clientT, Link]
  );

  useEffect(() => {
    // This effect checks to see if the result of pressing a button was a navigation
    // if so, close the settings bar.
    if (open) {
      setOpen(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [location.pathname]);

  return (
    <>
      <IconButton
        ref={anchorRef}
        edge="end"
        sx={{
          padding: 0,
          marginLeft: theme.spacing(1),
          marginRight: theme.spacing(1)
        }}
        onClick={() => setOpen(!open)}
        onMouseUp={e => e.stopPropagation()}
        size="large"
      >
        <AppUserAvatar alt={user.name} url={user.avatar} email={user.email} id="user-avatar">
          {user.name
            .split(' ', 2)
            .map(n => n[0].toUpperCase())
            .join('')}
        </AppUserAvatar>
      </IconButton>
      <ClickAwayListener onClickAway={() => setOpen(false)} mouseEvent="onMouseUp">
        <Popper
          sx={{ zIndex: theme.zIndex.appBar + 200, minWidth: '280px' }}
          open={open}
          anchorEl={anchorRef.current}
          placement="bottom-end"
          transition
        >
          {({ TransitionProps }) => (
            <Fade {...TransitionProps} timeout={250}>
              <Paper
                style={{
                  padding: theme.spacing(1),
                  maxHeight: 'calc(100vh - 80px)',
                  display: 'flex',
                  flexDirection: 'column'
                }}
                elevation={4}
              >
                <List
                  disablePadding
                  sx={{
                    position: 'sticky',
                    top: 0,
                    zIndex: 1,
                    boxShadow: 0,
                    borderRadius: 0,
                    borderBottom: `1px solid ${theme.palette.divider}`
                  }}
                  component={Paper}
                  elevation={4}
                >
                  <ListItem disableGutters dense>
                    <Box
                      sx={{
                        display: 'flex',
                        paddingTop: 2,
                        paddingBottom: 2,
                        paddingLeft: 3,
                        paddingRight: 3,
                        alignItems: 'center'
                      }}
                    >
                      <AppAvatar
                        sx={{ width: theme.spacing(8), height: theme.spacing(8) }}
                        alt={user.name}
                        url={user.avatar}
                        email={user.email}
                      >
                        {user.name
                          .split(' ', 2)
                          .map(n => n[0].toUpperCase())
                          .join('')}
                      </AppAvatar>
                      <Box sx={{ paddingLeft: 2 }}>
                        <Typography variant="body1" noWrap>
                          <b>{user.name}</b>
                        </Typography>
                        <Typography variant="caption" noWrap>
                          {user.email}
                        </Typography>
                      </Box>
                    </Box>
                  </ListItem>
                </List>

                <Box sx={{ overflowY: 'auto', flex: 1, pt: 1 }}>
                  {renderSlot('topnav.profile.slots.top', topnav.profile?.slots?.top)}
                  {renderFocusMode()}
                  {renderSlot('topnav.profile.slots.userMenu.before', topnav.profile?.slots?.userMenu?.before)}
                  {renderMenu(
                    'usermenu',
                    topnav.profile?.menus?.user?.slot,
                    topnav.profile?.menus?.user?.title,
                    topnav.profile?.menus?.user?.i18nKey,
                    hasContentBeforeUserMenu,
                    hasContentBeforeUserMenu
                  )}
                  {renderSlot('topnav.profile.slots.userMenu.after', topnav.profile?.slots?.userMenu?.after)}
                  {user.is_admin && (
                    <>
                      {renderSlot('topnav.profile.slots.admin.before', topnav.profile?.slots?.admin?.before)}
                      {renderMenu(
                        'adminmenu',
                        topnav.profile?.menus?.admin?.slot,
                        topnav.profile?.menus?.admin?.title,
                        topnav.profile?.menus?.admin?.i18nKey
                      )}
                      {renderSlot('topnav.profile.slots.admin.after', topnav.profile?.slots?.admin?.after)}
                    </>
                  )}
                  {renderThemeSelection(topnav.themeSelectionMode === 'profile')}
                  {renderSlot('topnav.profile.slots.bottom', topnav.profile?.slots?.bottom)}
                </Box>
              </Paper>
            </Fade>
          )}
        </Popper>
      </ClickAwayListener>
    </>
  );
};
