import { memo, type FC, type PropsWithChildren } from 'react';
import { PageContent } from './PageContent';

type PageFullWidthProps = PropsWithChildren & {
  height?: number | string;
  margin?: number;
  mb?: number;
  ml?: number;
  mr?: number;
  mt?: number;
};

const PageFullWidthInternal: FC<PageFullWidthProps> = ({
  children,
  height,
  margin = null,
  mb = 2,
  ml = 2,
  mr = 2,
  mt = 2
}) => {
  return (
    <PageContent width="100%" height={height} margin={margin} mb={mb} ml={ml} mr={mr} mt={mt}>
      {children}
    </PageContent>
  );
};

export const PageFullWidth = memo(PageFullWidthInternal);
